UPDATE abs_material_info 
SET name = {name}, type = {type}, size = {size}, category = {category}, duration = {duration}, word_count = {wordCount}, tags = {tags}, content = {content}, file_path = {filePath}, upload_time = {uploadTime}, status = {status}, create_user = {createUser} 
WHERE rowguid = {rowguid}
